pub(crate) fn translate_ja(en: &str) -> &str {
    lookup_ja(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_ja(en: &str) -> bool {
    lookup_ja(en).is_some()
}

