pub(crate) fn translate_ko(en: &str) -> &str {
    lookup_ko(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_ko(en: &str) -> bool {
    lookup_ko(en).is_some()
}

