pub(crate) fn translate_nl(en: &str) -> &str {
    lookup_nl(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_nl(en: &str) -> bool {
    lookup_nl(en).is_some()
}

